inline const AbilRow* abil_info(unsigned id) {
    int lo = 0, hi = ABILS_N - 1;
    while (lo <= hi) { int mid = (lo + hi) >> 1;
        if (ABILS[mid].id == id) return &ABILS[mid];
        if (ABILS[mid].id < id) lo = mid + 1; else hi = mid - 1; }
    return 0;
}

